typedef struct Node {
    int key, value;
    struct Node *prev, *next;
} Node;

typedef struct {
    int cap, size;
    Node *head, *tail;
    Node **map; // key -> Node*
} LruCache;

LruCache* createCache(int cap) {
    LruCache* c = malloc(sizeof(LruCache));
    c->cap = cap;
    c->size = 0;
    c->head = c->tail = NULL;
    c->map = calloc(10001, sizeof(Node*));
    return c;
}

void moveToFront(LruCache* c, Node* n) {
    if (c->head == n) return;
    if (n->prev) n->prev->next = n->next;
    if (n->next) n->next->prev = n->prev;
    if (c->tail == n) c->tail = n->prev;
    n->prev = NULL;
    n->next = c->head;
    if (c->head) c->head->prev = n;
    c->head = n;
    if (!c->tail) c->tail = n;
}

int getValue(LruCache* c, int key) {
    Node* n = c->map[key];
    if (!n) return -1;
    moveToFront(c, n);
    return n->value;
}

void putValue(LruCache* c, int key, int value) {
    if (c->cap == 0) return;

    Node* n = c->map[key];
    if (n) {
        n->value = value;
        moveToFront(c, n);
        return;
    }

    if (c->size == c->cap) {
        Node* lru = c->tail;
        c->map[lru->key] = NULL;
        c->tail = lru->prev;
        if (c->tail) c->tail->next = NULL;
        else c->head = NULL;
        free(lru);
        c->size--;
    }

    Node* node = malloc(sizeof(Node));
    node->key = key;
    node->value = value;
    node->prev = NULL;
    node->next = c->head;
    if (c->head) c->head->prev = node;
    c->head = node;
    if (!c->tail) c->tail = node;
    c->map[key] = node;
    c->size++;
}

code.Java:
class LruCache {
    private int cap;
    private LinkedHashMap<Integer, Integer> map;

    public LruCache(int cacheCapacity) {
        cap = cacheCapacity;
        map = new LinkedHashMap<>(16, 0.75f, true) {
            protected boolean removeEldestEntry(Map.Entry<Integer, Integer> e) {
                return size() > cap;
            }
        };
    }

    public int getValue(int key) {
        return map.getOrDefault(key, -1);
    }

    public void putValue(int key, int value) {
        if (cap == 0) return;
        map.put(key, value);
    }
}

